const data = $input.item.json;
const path = require('path');
return { json: {
  path:     data.path || '',
  filename: path.basename(data.path||'untitled', path.extname(data.path||'')),
  text:     data.text || data.extractedText || data.content || '',
  source:   'pdf'
}};

const fs   = require('fs');
const path = require('path');
const filePath = $input.item.json.path;
let content;
try { content = fs.readFileSync(filePath, 'utf8'); }
catch (err) { throw new Error(`[ReadText] Cannot read ${filePath}: ${err.message}`); }
return { json: { path: filePath, filename: path.basename(filePath, path.extname(filePath)), text: content, source: 'text' } };

const fs   = require('fs');
const logPath = `${process.env.OBSIDIAN_VAULT_PATH}/00_Inbox/_errors.log`;
const msg     = `[${new Date().toISOString()}] UNSUPPORTED: ${$input.item.json.path}\n`;
try { fs.appendFileSync(logPath, msg); } catch (e) { console.error('Log write failed:', e.message); }
return { json: { skipped: true, path: $input.item.json.path } };

const fs   = require('fs');
const path = require('path');

const vaultPath   = process.env.OBSIDIAN_VAULT_PATH;
const promptPath  = process.env.MASTER_ARCHITECT_PROMPT_PATH;
const cacheMaxAge = parseInt(process.env.SNAPSHOT_CACHE_MINUTES || '5') * 60 * 1000;
const cacheFile   = path.join(vaultPath, '04_Meta', '.snapshot_cache.json');

// ── FIX #3 — Load master prompt with inline fallback ─────────────
let masterPrompt = null;
if (promptPath) {
  try {
    masterPrompt = fs.readFileSync(promptPath, 'utf8');
    if (!masterPrompt || masterPrompt.trim() === '') masterPrompt = null;
  } catch (err) {
    console.warn(`[Snapshot] Cannot read prompt file ${promptPath}: ${err.message}. Using inline fallback.`);
  }
}
if (!masterPrompt) {
  // Inline minimal fallback so ingestion never dies on a missing file
  masterPrompt = `You are the Recursive Cognitive Engine. Decompose the source document into 8-12 interconnected Obsidian Markdown notes. Return ONLY a single valid JSON object matching this schema: { "batch_id": "<ISO timestamp>", "source_title": "<title>", "notes": [{ "filename": "01_Index_<Slug>.md", "folder": "01_Wiki_Nodes", "content": "<full markdown>" }], "lesson_cemetery_candidates": [], "experiment_24h": { "title": "", "hypothesis": "", "steps": [], "success_metric": "", "ai_automation_angle": "" }, "mermaid_challenge": "", "council_debate_summary": "" }. VAULT SNAPSHOT: {{VAULT_SNAPSHOT}} SOURCE TITLE: {{SOURCE_TITLE}} SOURCE TEXT: {{SOURCE_TEXT}}`;
  console.warn('[Snapshot] USING INLINE FALLBACK PROMPT. Set MASTER_ARCHITECT_PROMPT_PATH for full functionality.');
}

// ── FIX #8 — Snapshot cache ────────────────────────────────────────
let snapshot = null;
try {
  if (fs.existsSync(cacheFile)) {
    const cacheRaw  = fs.readFileSync(cacheFile, 'utf8');
    const cacheData = JSON.parse(cacheRaw);
    const age       = Date.now() - new Date(cacheData.cached_at).getTime();
    if (age < cacheMaxAge) {
      snapshot = cacheData.snapshot;
      console.log(`[Snapshot] Using cached snapshot (${Math.round(age/1000)}s old, max ${cacheMaxAge/1000}s).`);
    }
  }
} catch (_) { /* cache miss — fall through to full scan */ }

if (!snapshot) {
  function scanDir(dir, base) {
    base = base || '';
    let results = [];
    if (!fs.existsSync(dir)) return results;
    let items;
    try { items = fs.readdirSync(dir); } catch (e) { return results; }
    for (const item of items) {
      const full = path.join(dir, item);
      const rel  = path.join(base, item);
      let stat;
      try { stat = fs.statSync(full); } catch (_) { continue; }
      if (stat.isDirectory() && !item.startsWith('.')) {
        results = results.concat(scanDir(full, rel));
      } else if (item.endsWith('.md')) {
        results.push({ name: path.basename(item, '.md'), folder: base || 'root', mtime: stat.mtime.toISOString() });
      }
    }
    return results;
  }

  const allNotes = scanDir(vaultPath);
  snapshot = {
    total_notes:    allNotes.length,
    wiki_nodes:     allNotes.filter(n => n.folder.startsWith('01_Wiki_Nodes')).map(n => n.name),
    council_notes:  allNotes.filter(n => n.folder.startsWith('02_The_Council')).map(n => n.name),
    lesson_cemetery:allNotes.filter(n => n.folder.startsWith('03_Lesson_Cemetery')).map(n => n.name),
    all_note_names: allNotes.map(n => n.name),
    snapshot_time:  new Date().toISOString()
  };

  // Write cache
  try {
    fs.mkdirSync(path.join(vaultPath, '04_Meta'), { recursive: true });
    fs.writeFileSync(cacheFile, JSON.stringify({ cached_at: new Date().toISOString(), snapshot }, null, 2), 'utf8');
  } catch (e) { console.warn('[Snapshot] Could not write cache:', e.message); }
}

const prevData = $input.item.json;
return {
  json: {
    ...prevData,
    vault_snapshot:      snapshot,
    vault_snapshot_text: JSON.stringify(snapshot, null, 2),
    master_prompt:       masterPrompt,
    using_fallback_prompt: masterPrompt.includes('Inline minimal fallback')
  }
};

const fs   = require('fs');
const path = require('path');

const data           = $input.item.json;
const MAX_CHARS      = parseInt(process.env.SOURCE_TEXT_MAX_CHARS || '60000');
// Rough heuristic: 1 token ≈ 4 chars; Claude Sonnet context ≈ 180K tokens input
const HARD_LIMIT     = 180000 * 4;
const rawText        = data.text || data.extractedText || data.content || '';
const sourceChars    = rawText.length;

let truncated        = false;
let processedText    = rawText;
let truncationNote   = '';

if (sourceChars > HARD_LIMIT) {
  processedText  = rawText.substring(0, HARD_LIMIT);
  truncated      = true;
  truncationNote = `⚠️ Source truncated from ${sourceChars.toLocaleString()} chars to ${HARD_LIMIT.toLocaleString()} (hard context limit).`;
  console.warn('[TokenGuard]', truncationNote);
} else if (sourceChars > MAX_CHARS) {
  processedText  = rawText.substring(0, MAX_CHARS);
  truncated      = true;
  truncationNote = `⚠️ Source truncated from ${sourceChars.toLocaleString()} to ${MAX_CHARS.toLocaleString()} chars (SOURCE_TEXT_MAX_CHARS).`;
  console.warn('[TokenGuard]', truncationNote);
}

// Log truncation to vault if it happened
if (truncated) {
  try {
    const vaultPath = process.env.OBSIDIAN_VAULT_PATH;
    const logDir    = path.join(vaultPath, '04_Meta');
    fs.mkdirSync(logDir, { recursive: true });
    const logPath   = path.join(logDir, 'truncation_log.md');
    const entry     = `| ${new Date().toISOString()} | ${data.filename || 'unknown'} | ${sourceChars} → ${processedText.length} chars |\n`;
    if (!fs.existsSync(logPath)) {
      fs.writeFileSync(logPath, `# ✂️ Source Truncation Log\n\n| Timestamp | Source | Chars (before → after) |\n|-----------|--------|-----------------------|\n`, 'utf8');
    }
    fs.appendFileSync(logPath, entry, 'utf8');
  } catch (e) { console.warn('[TokenGuard] Could not write truncation log:', e.message); }
}

return {
  json: {
    ...data,
    text:             processedText,
    source_chars_raw: sourceChars,
    source_truncated: truncated,
    truncation_note:  truncationNote
  }
};

const https = require('https');

const data       = $input.item.json;
const model      = process.env.CLAUDE_MODEL || 'claude-sonnet-4-6';
const maxTokens  = parseInt(process.env.CLAUDE_MAX_TOKENS || '8192');
const maxChars   = parseInt(process.env.SOURCE_TEXT_MAX_CHARS || '60000');
const apiKey     = process.env.ANTHROPIC_API_KEY;

if (!apiKey) throw new Error('[Decompose] ANTHROPIC_API_KEY env var is not set.');

const prompt = (data.master_prompt || '')
  .replace('{{VAULT_SNAPSHOT}}', data.vault_snapshot_text || '{}')
  .replace('{{SOURCE_TITLE}}',   data.filename            || 'Untitled Source')
  .replace('{{SOURCE_TEXT}}',    (data.text || data.extractedText || '').substring(0, maxChars))
  .replace('{{DATE}}',           new Date().toISOString().split('T')[0]);

const requestBody = {
  model,
  max_tokens: maxTokens,
  temperature: 0.3,
  system: data.master_prompt || '',
  messages: [{ role: 'user', content: prompt }]
};

// ── Exponential backoff with full jitter ──────────────────────────────────────
// delay(attempt) = min(BASE * 2^attempt, CAP) * random(0.5, 1.5)
const BASE_MS  = 2000;
const CAP_MS   = 60000;
const MAX_TRIES = parseInt(process.env.CLAUDE_MAX_RETRIES || '4');

async function callClaude(body) {
  const bodyStr = JSON.stringify(body);
  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.anthropic.com',
      path:     '/v1/messages',
      method:   'POST',
      headers: {
        'x-api-key':         apiKey,
        'anthropic-version': '2023-06-01',
        'content-type':      'application/json',
        'content-length':    Buffer.byteLength(bodyStr)
      }
    }, res => {
      let raw = '';
      res.on('data', c => raw += c);
      res.on('end', () => {
        const retryable = res.statusCode === 429 || res.statusCode >= 500;
        if (res.statusCode !== 200) {
          reject({ status: res.statusCode, body: raw.substring(0, 400), retryable });
        } else {
          try { resolve(JSON.parse(raw)); }
          catch (e) { reject({ message: 'JSON parse error', body: raw.substring(0, 200), retryable: false }); }
        }
      });
    });
    req.on('error', e => reject({ message: e.message, retryable: true }));
    req.setTimeout(120000, () => { req.destroy(); reject({ message: 'Request timeout', retryable: true }); });
    req.write(bodyStr);
    req.end();
  });
}

let lastErr;
for (let attempt = 0; attempt < MAX_TRIES; attempt++) {
  try {
    const result = await callClaude(requestBody);
    console.log(`[Decompose] Success on attempt ${attempt + 1}. Input tokens: ${result.usage?.input_tokens}, Output: ${result.usage?.output_tokens}`);
    return { json: { ...result, _source_path: data.path || '', _attempt: attempt + 1 } };
  } catch (err) {
    lastErr = err;
    if (!err.retryable) break;
    if (attempt < MAX_TRIES - 1) {
      const jitter = 0.5 + Math.random();  // [0.5, 1.5]
      const delay  = Math.min(BASE_MS * Math.pow(2, attempt), CAP_MS) * jitter;
      console.warn(`[Decompose] Attempt ${attempt + 1} failed (${err.status || err.message}). Retrying in ${Math.round(delay)}ms...`);
      await new Promise(r => setTimeout(r, delay));
    }
  }
}

throw new Error(`[Decompose] All ${MAX_TRIES} attempts failed. Last error: ${JSON.stringify(lastErr).substring(0, 400)}`);

const response = $input.item.json;
let rawText = '';

if (response.content && Array.isArray(response.content)) {
  rawText = response.content.filter(b => b.type === 'text').map(b => b.text).join('');
} else if (typeof response === 'string') { rawText = response; }

rawText = rawText.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();

let parsed;
try { parsed = JSON.parse(rawText); } catch (e) {
  const m = rawText.match(/\{[\s\S]*\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch (e2) {
    throw new Error(`JSON parse failed: ${e2.message}. Raw (500): ${rawText.substring(0,500)}`);
  }} else { throw new Error(`No JSON in response. Raw: ${rawText.substring(0,200)}`); }
}

if (!parsed.notes || !Array.isArray(parsed.notes)) throw new Error('Missing notes array');
if (parsed.notes.length === 0) throw new Error('Claude returned empty notes array');

// ── FIX #9 — Safe field extraction with defaults ──────────────────
const REQUIRED = ['filename', 'folder', 'content'];
const BAD      = new Set(['undefined', 'null', '']);
for (let i = 0; i < parsed.notes.length; i++) {
  const note = parsed.notes[i];
  for (const field of REQUIRED) {
    const val = note[field];
    if (val === undefined || val === null || typeof val !== 'string') {
      throw new Error(`Note[${i}].${field} is ${val === null ? 'null' : typeof val}. Preview: ${JSON.stringify(note).substring(0,200)}`);
    }
    if (BAD.has(val.trim().toLowerCase())) {
      throw new Error(`Note[${i}].${field} has bad literal value: "${val}"`);
    }
    if (field === 'filename' && /[/\\]/.test(val)) {
      throw new Error(`Note[${i}].filename contains path separator: "${val}". Prompt injection blocked.`);
    }
  }
}

// ── FIX #9 — Safe optional field defaults ────────────────────────
parsed.council_debate_summary    = (typeof parsed.council_debate_summary === 'string')    ? parsed.council_debate_summary    : '';
parsed.mermaid_challenge         = (typeof parsed.mermaid_challenge       === 'string')    ? parsed.mermaid_challenge         : '';
parsed.lesson_cemetery_candidates= Array.isArray(parsed.lesson_cemetery_candidates)        ? parsed.lesson_cemetery_candidates : [];
parsed.experiment_24h            = (parsed.experiment_24h && typeof parsed.experiment_24h === 'object') ? parsed.experiment_24h : {};

// Carry source path and vault snapshot info for downstream nodes
parsed._source_path      = $input.item.json.path     || $input.item.json._source_path || '';
parsed._source_filename  = $input.item.json.filename || 'Unknown';
parsed._parse_time       = new Date().toISOString();
parsed._vault_wiki_nodes = ($input.item.json.vault_snapshot || {}).wiki_nodes || [];

console.log(`✅ Parsed and validated ${parsed.notes.length} notes`);
return { json: parsed };

const fs   = require('fs');
const path = require('path');

const vaultPath = process.env.OBSIDIAN_VAULT_PATH;
const data      = $input.item.json;
const batchId   = data.batch_id || new Date().toISOString();
const safeId    = batchId.replace(/[:.]/g, '-').substring(0, 24);

const stagingDir = path.join(vaultPath, '04_Meta', '_staging');
try { fs.mkdirSync(stagingDir, { recursive: true }); } catch (e) {}

// Build a human-readable preview
const noteList = (data.notes || []).map((n, i) =>
  `${i + 1}. \`${n.folder}/${n.filename}\`\n   ${(n.content || '').split('\n').find(l => l.startsWith('title:')) || '(no title in frontmatter)'}`
).join('\n');

const cemetaryList = (data.lesson_cemetery_candidates || []).map(c =>
  `- 🪦 **${c.original_filename}** — ${c.error_type}: ${(c.reason || '').substring(0, 100)}`
).join('\n') || '_None_';

const previewContent = `---
title: "⏳ Pending Review: ${data.source_title || 'Unknown'}"
date: "${new Date().toISOString().split('T')[0]}"
tags: [review-pending, ai-generated]
batch_id: "${batchId}"
status: pending-review
---

# ⏳ Pending Review: ${data.source_title || 'Unknown Source'}

> **Batch ID:** \`${batchId}\`
> **Generated at:** ${new Date().toISOString()}
> **Source file:** ${data.filename || 'Unknown'}
${data.source_truncated ? `> **⚠️ Source truncated:** ${data.truncation_note}` : ''}
${data.using_fallback_prompt ? '> **⚠️ Fallback prompt used — verify note quality**' : ''}

## Proposed Notes (${(data.notes || []).length})

${noteList || '_No notes generated_'}

## Lesson Cemetery Candidates

${cemetaryList}

## Council Summary (Preview)

${(data.council_debate_summary || '').substring(0, 500) || '_No council summary_'}

## 24h Experiment

**${data.experiment_24h?.title || 'None'}**
${data.experiment_24h?.hypothesis || ''}

---
_Approve or reject this batch in n8n. If HUMAN_REVIEW_ENABLED=false this note is auto-approved._
`;

const previewPath = path.join(stagingDir, `review_${safeId}.md`);
try {
  fs.writeFileSync(previewPath, previewContent, 'utf8');
} catch (err) {
  throw new Error(`[Staging] Cannot write preview note: ${err.message}`);
}

console.log(`[Staging] Preview written: ${previewPath}`);
return {
  json: {
    ...data,
    _staging_preview_path: previewPath,
    _batch_safe_id:        safeId
  }
};

const fs   = require('fs');
const path = require('path');

const vaultPath = process.env.OBSIDIAN_VAULT_PATH;
const data      = $input.item.json;

const previewPath = data._staging_preview_path || data.body?._staging_preview_path;
const batchId     = data._batch_safe_id         || data.body?._batch_safe_id || 'unknown';

// ── 1. Delete the staging preview note ───────────────────────────────────────
if (previewPath) {
  try {
    fs.unlinkSync(previewPath);
    console.log(`[Reject] Deleted staging preview: ${previewPath}`);
  } catch (e) {
    console.warn(`[Reject] Could not delete preview (${previewPath}): ${e.message}`);
  }
}

// ── 2. Release the .processing file lock ─────────────────────────────────────
// The source file was renamed to <name>.processing at the start of the pipeline.
// On rejection we move it to 00_Inbox/_rejected/ with original extension restored,
// so the user can inspect it and re-submit manually.
const sourcePath = data._source_path || data.body?._source_path || '';
if (sourcePath && fs.existsSync(sourcePath)) {
  const rejectedDir = path.join(vaultPath, '00_Inbox', '_rejected');
  try {
    fs.mkdirSync(rejectedDir, { recursive: true });
    const rawBase    = path.basename(sourcePath);
    const cleanBase  = rawBase.endsWith('.processing')
      ? rawBase.slice(0, -'.processing'.length)
      : rawBase;
    const ts         = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
    const rejPath    = path.join(rejectedDir, `${ts}_${cleanBase}`);
    fs.renameSync(sourcePath, rejPath);
    console.log(`[Reject] Source file moved to rejected: ${rejPath}`);
  } catch (e) {
    // Non-fatal: best-effort unlock. Log it, don't crash.
    console.warn(`[Reject] Could not move source to _rejected: ${e.message}`);
    // Attempt a plain rename back (strip .processing)
    try {
      const cleanPath = sourcePath.replace(/\.processing$/, '');
      if (cleanPath !== sourcePath) {
        fs.renameSync(sourcePath, cleanPath);
        console.log(`[Reject] Fallback: renamed ${sourcePath} → ${cleanPath}`);
      }
    } catch (_) {}
  }
}

// ── 3. Log the rejection ─────────────────────────────────────────────────────
try {
  const logPath = path.join(vaultPath, '04_Meta', 'processing_log.md');
  const entry   = `| ${new Date().toISOString()} | ${data.source_title || batchId} | 0 notes | ❌ REJECTED |\n`;
  if (!fs.existsSync(logPath)) {
    fs.writeFileSync(logPath, `# 📋 Processing Log\n\n| Timestamp | Source | Notes | Status |\n|-----------|--------|-------|--------|\n`, 'utf8');
  }
  fs.appendFileSync(logPath, entry, 'utf8');
} catch (e) {
  console.warn(`[Reject] Could not write processing log: ${e.message}`);
}

console.log(`[Reject] Batch ${batchId} rejected and cleaned up.`);
return { json: { status: 'rejected', batch_id: batchId, source_released: !!sourcePath } };

const fs   = require('fs');
const path = require('path');

const vaultPath     = process.env.OBSIDIAN_VAULT_PATH;
const resolvedVault = path.resolve(vaultPath);
const note          = $input.item.json;

// ── Security: sanitise filename and folder ────────────────────────
const rawFilename = (note.filename || 'untitled.md');
const safeFilename = rawFilename
  .replace(/\.\.[/\\]/g, '')
  .replace(/^[/\\]+/, '')
  .replace(/[<>:"/\\|?*]/g, '-')
  .replace(/\s+/g, '_')
  .replace(/-{2,}/g, '-');

if (!safeFilename || safeFilename === '.md' || safeFilename === '-') {
  throw new Error(`[WriteNote] Sanitised filename invalid. Original: "${rawFilename}"`);
}

const rawFolder    = (note.folder || '01_Wiki_Nodes').replace(/\.\.[/\\]/g, '').replace(/^[/\\]+/, '');
const targetFolder = path.resolve(resolvedVault, rawFolder);

if (!targetFolder.startsWith(resolvedVault + path.sep) && targetFolder !== resolvedVault) {
  throw new Error(`SECURITY: folder "${note.folder}" escapes vault root. Write blocked.`);
}

try { fs.mkdirSync(targetFolder, { recursive: true }); } catch (e) {
  throw new Error(`Cannot create folder ${targetFolder}: ${e.message}`);
}

const fullPath     = path.join(targetFolder, safeFilename);
const resolvedFull = path.resolve(fullPath);
if (!resolvedFull.startsWith(resolvedVault + path.sep)) {
  throw new Error(`SECURITY: resolved path "${resolvedFull}" escapes vault root. Write blocked.`);
}

// ── FIX #6 — Merge Intelligence ───────────────────────────────────
// Check if an existing note shares the same concept slug (title minus prefix number)
// e.g., "02_Entity_RecursiveLearning" matches "02_Entity_RecursiveLearning"
// If matched, APPEND an update section rather than create a duplicate.
const newContent = note.content || '';

function extractSlug(fname) {
  return fname.replace(/\.md$/, '').replace(/^\d+_[^_]+_/, '').toLowerCase().replace(/[_-]+/g, ' ');
}

const newSlug = extractSlug(safeFilename);
let mergeTarget = null;

// Check vault snapshot for potential merge targets (passed through pipeline)
const wikiNodes = (note._vault_wiki_nodes || []);
for (const existingName of wikiNodes) {
  if (existingName.toLowerCase() === safeFilename.replace('.md','').toLowerCase()) {
    // Exact name match — this is handled by versioning below, not merging
    break;
  }
  const existingSlug = extractSlug(existingName + '.md');
  // Simple edit-distance proxy: if slugs share > 70% of words, treat as mergeable
  const newWords      = new Set(newSlug.split(' ').filter(w => w.length > 3));
  const existingWords = new Set(existingSlug.split(' ').filter(w => w.length > 3));
  if (newWords.size === 0) break;
  const intersection  = [...newWords].filter(w => existingWords.has(w)).length;
  const overlap       = intersection / Math.max(newWords.size, existingWords.size);
  if (overlap >= 0.70) {
    mergeTarget = existingName;
    break;
  }
}

if (mergeTarget) {
  // Merge: find existing file in 01_Wiki_Nodes and append update section
  const existingPath = path.join(resolvedVault, '01_Wiki_Nodes', mergeTarget + '.md');
  if (fs.existsSync(existingPath)) {
    try {
      const updateSection = `\n\n---\n\n## 🔄 Update — ${new Date().toISOString().split('T')[0]}\n\n> _Merged from: ${safeFilename}_\n\n${newContent.split('---').slice(2).join('---').trim()}`;
      // Atomic merge: read → modify → write via tmp
      const existingContent = fs.readFileSync(existingPath, 'utf8');
      const mergedContent   = existingContent + updateSection;
      const mergeTmp        = existingPath + '.tmp';
      fs.writeFileSync(mergeTmp, mergedContent, 'utf8');
      fs.renameSync(mergeTmp, existingPath);
      console.log(`🔀 Merged into existing note: ${mergeTarget}.md`);
      return { json: { status: 'merged', merged_into: mergeTarget, filename: safeFilename } };
    } catch (e) {
      console.warn(`[WriteNote] Merge failed (${e.message}), falling through to normal write.`);
    }
  }
}

// ── Normal write path ─────────────────────────────────────────────
try {
  if (fs.existsSync(fullPath)) {
    let existing;
    try { existing = fs.readFileSync(fullPath, 'utf8'); } catch (e) {
      throw new Error(`Cannot read existing ${fullPath}: ${e.message}`);
    }
    if (existing.trim() === newContent.trim()) {
      console.log(`⏭️ Skipped duplicate: ${safeFilename}`);
      return { json: { status: 'skipped_duplicate', filename: safeFilename } };
    }
    const ts = Date.now();
    try { fs.renameSync(fullPath, fullPath.replace(/\.md$/, `_v${ts}.md`)); } catch (e) {
      throw new Error(`Cannot version ${fullPath}: ${e.message}`);
    }

    // ── Version pruning ────────────────────────────────────────────
    const MAX_VERSIONS = parseInt(process.env.MAX_NOTE_VERSIONS || '5');
    const base         = safeFilename.replace(/\.md$/, '');
    const escaped      = base.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const vPat         = new RegExp(`^${escaped}_v\\d+\\.md$`);
    let   siblings     = [];
    try { siblings = fs.readdirSync(targetFolder); } catch (_) {}
    const old = siblings.filter(f => vPat.test(f)).sort();
    while (old.length > MAX_VERSIONS) {
      const oldest = old.shift();
