      catch (e) { console.warn(`Prune failed (${oldest}): ${e.message}`); }
    }
  }

  // Atomic write: write to .tmp then rename to avoid partial-write corruption
  const tmpPath = fullPath + '.tmp';
  fs.writeFileSync(tmpPath, newContent, 'utf8');
  fs.renameSync(tmpPath, fullPath);
  console.log(`✅ Written: ${fullPath}`);
  return { json: { status: 'written', filename: safeFilename, folder: note.folder,
                   path: fullPath, bytes: Buffer.byteLength(newContent, 'utf8') } };
} catch (err) {
  throw new Error(`[WriteNote] ${err.message}`);
}

