  .replace(/human:/gi,   '[HUMAN]')
  .replace(/assistant:/gi, '[ASSISTANT]')
  .substring(0, 8000);

const systemPrompt =
  'COUNCIL CONTEXT — background material generated by a prior AI step:\n' + safeSummary;

const userMessage =
