  temperature: 0.7,
  system: systemPrompt,
  messages: [{ role: 'user', content: userMessage }]
};

// ── Exponential backoff with full jitter ──────────────────────────────────────
const BASE_MS   = 2000;
const CAP_MS    = 60000;
const MAX_TRIES = parseInt(process.env.CLAUDE_MAX_RETRIES || '4');

async function callClaude(body) {
  const bodyStr = JSON.stringify(body);
  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.anthropic.com',
      path:     '/v1/messages',
      method:   'POST',
      headers: {
        'x-api-key':         apiKey,
        'anthropic-version': '2023-06-01',
        'content-type':      'application/json',
        'content-length':    Buffer.byteLength(bodyStr)
      }
    }, res => {
      let raw = '';
      res.on('data', c => raw += c);
      res.on('end', () => {
        const retryable = res.statusCode === 429 || res.statusCode >= 500;
        if (res.statusCode !== 200) {
          reject({ status: res.statusCode, body: raw.substring(0, 400), retryable });
        } else {
          try { resolve(JSON.parse(raw)); }
          catch (e) { reject({ message: 'JSON parse error', body: raw.substring(0, 200), retryable: false }); }
        }
      });
    });
    req.on('error', e => reject({ message: e.message, retryable: true }));
    req.setTimeout(90000, () => { req.destroy(); reject({ message: 'Request timeout', retryable: true }); });
    req.write(bodyStr);
    req.end();
  });
}

let lastErr;
for (let attempt = 0; attempt < MAX_TRIES; attempt++) {
  try {
    const result = await callClaude(requestBody);
    console.log(`[Council] Success on attempt ${attempt + 1}. Tokens: ${result.usage?.output_tokens}`);
    return { json: { ...result, _attempt: attempt + 1 } };
  } catch (err) {
    lastErr = err;
    if (!err.retryable) break;
    if (attempt < MAX_TRIES - 1) {
      const jitter = 0.5 + Math.random();
      const delay  = Math.min(BASE_MS * Math.pow(2, attempt), CAP_MS) * jitter;
      console.warn(`[Council] Attempt ${attempt + 1} failed (${err.status || err.message}). Retrying in ${Math.round(delay)}ms...`);
      await new Promise(r => setTimeout(r, delay));
    }
  }
}

throw new Error(`[Council] All ${MAX_TRIES} attempts failed. Last: ${JSON.stringify(lastErr).substring(0, 400)}`);

