const fs   = require('fs');
const path = require('path');

const data        = $input.item.json;
const staleNotes  = data.stale_notes  || [];
const orphanNotes = data.orphan_notes || [];
const allTitles   = data.all_titles   || [];
const vaultPath   = process.env.OBSIDIAN_VAULT_PATH;
const wikiFolder  = path.join(vaultPath, '01_Wiki_Nodes');
const SIM_THRESH  = parseFloat(process.env.SEMANTIC_SIM_THRESHOLD || '0.72');

// ── Helpers ──────────────────────────────────────────────────────────────────
function tokenize(text) {
  return text.toLowerCase()
    .replace(/---[\s\S]*?---/, '')          // strip YAML frontmatter
    .replace(/```[\s\S]*?```/g, '')         // strip code blocks
    .replace(/[^a-z0-9\s]/g, ' ')
    .split(/\s+/)
    .filter(w => w.length > 2 && !STOPWORDS.has(w));
}

const STOPWORDS = new Set([
  'the','and','for','are','but','not','you','all','can','had','her',
  'was','one','our','out','day','get','has','him','his','how','its',
  'may','new','now','old','see','two','way','who','with','this','that',
  'from','they','been','have','more','will','also','into','than','then',
  'when','what','some','each','make','like','time','just','know','take',
  'year','your','good','much','well','very','after','back','first','great',
  'long','made','many','most','over','such','used','work'
]);

function buildTFIDF(docs) {
  // TF: term freq normalised per doc
  const tf = docs.map(tokens => {
    const freq = {};
    for (const t of tokens) freq[t] = (freq[t] || 0) + 1;
    const total = tokens.length || 1;
    Object.keys(freq).forEach(k => freq[k] /= total);
    return freq;
  });
  // IDF: log(N / df)
  const df = {};
  for (const freq of tf)
    for (const t of Object.keys(freq)) df[t] = (df[t] || 0) + 1;
  const N = docs.length;
  const idf = {};
  for (const t of Object.keys(df)) idf[t] = Math.log((N + 1) / (df[t] + 1)) + 1;
  // TF-IDF vectors
  return tf.map(freq => {
    const vec = {};
    for (const [t, v] of Object.entries(freq)) vec[t] = v * (idf[t] || 1);
    return vec;
  });
}

function cosine(a, b) {
  const keys = new Set([...Object.keys(a), ...Object.keys(b)]);
  let dot = 0, mA = 0, mB = 0;
  for (const k of keys) {
    const va = a[k] || 0, vb = b[k] || 0;
    dot += va * vb; mA += va * va; mB += vb * vb;
  }
  return (mA && mB) ? dot / (Math.sqrt(mA) * Math.sqrt(mB)) : 0;
}

// ── Load note contents ────────────────────────────────────────────────────────
const candidates = [...staleNotes, ...orphanNotes];
if (candidates.length === 0) {
  console.log('[TF-IDF] No candidates to check. Skipping.');
  return { json: { ...data, semantic_duplicates: [], tfidf_mode: true } };
}

// Load candidate content + a sample of all wiki notes for IDF corpus
const corpus = [];
const loaded  = [];

// First load candidates
for (const note of candidates) {
  let content = '';
  try { content = fs.readFileSync(note.path || path.join(wikiFolder, note.file), 'utf8'); }
  catch (e) { console.warn(`[TF-IDF] Cannot read ${note.file}: ${e.message}`); }
  corpus.push(tokenize(content || note.file));
  loaded.push(note.file);
}

// Add up to 100 random vault notes for IDF richness
const allMd = allTitles.filter(f => f.endsWith('.md'));
const sample = allMd.sort(() => Math.random() - 0.5).slice(0, 100);
const sampleTokens = [];
for (const fname of sample) {
  let content = '';
  try { content = fs.readFileSync(path.join(wikiFolder, fname), 'utf8'); }
  catch (_) {}
  sampleTokens.push(tokenize(content || fname));
}

const allCorpus = [...corpus, ...sampleTokens];
const tfidfVecs = buildTFIDF(allCorpus);
const candidateVecs = tfidfVecs.slice(0, candidates.length);

// ── Pairwise cosine similarity on candidates ──────────────────────────────────
const duplicateGroups = [];
const grouped = new Set();

for (let i = 0; i < candidates.length; i++) {
  if (grouped.has(i)) continue;
  const group = [loaded[i]];
  for (let j = i + 1; j < candidates.length; j++) {
    if (grouped.has(j)) continue;
    const sim = cosine(candidateVecs[i], candidateVecs[j]);
    if (sim >= SIM_THRESH) {
      group.push(loaded[j]);
      grouped.add(j);
    }
  }
  if (group.length > 1) {
    grouped.add(i);
    duplicateGroups.push({
      group,
      reason: `TF-IDF cosine similarity ≥ ${SIM_THRESH} (local computation, zero API cost)`
    });
  }
}

console.log(`[TF-IDF] Checked ${candidates.length} candidates. Found ${duplicateGroups.length} duplicate groups.`);
return {
  json: {
    ...data,
    semantic_duplicates: duplicateGroups,
    tfidf_mode: true,
