if (!filePath || !fs.existsSync(filePath)) {
  throw new Error(`[Lock] File not found or already moved: ${filePath}`);
}

// Skip if already marked (idempotent guard)
if (filePath.endsWith('.processing')) {
  return { json: { ...$input.item.json, path: filePath } };
}

const lockedPath = filePath + '.processing';

// If a .processing twin already exists, a prior run crashed mid-flight.
// Remove the stale lock so this run can proceed cleanly.
if (fs.existsSync(lockedPath)) {
  console.warn(`[Lock] Stale lock found at ${lockedPath} — removing and re-locking.`);
  try { fs.unlinkSync(lockedPath); } catch (e) { /* ignore */ }
}

try {
  fs.renameSync(filePath, lockedPath);
  console.log(`[Lock] Renamed ${filePath} → ${lockedPath}`);
} catch (err) {
